DELETE FROM cash_movements
WHERE id IN ('16000000-0000-0000-0000-000000000001', '16000000-0000-0000-0000-000000000002');

DELETE FROM stock_movements
WHERE id IN ('15000000-0000-0000-0000-000000000001', '15000000-0000-0000-0000-000000000002');

DELETE FROM sale_items
WHERE id IN (
    '14000000-0000-0000-0000-000000000011',
    '14000000-0000-0000-0000-000000000012',
    '14000000-0000-0000-0000-000000000013'
);

DELETE FROM sales
WHERE id IN ('14000000-0000-0000-0000-000000000001', '14000000-0000-0000-0000-000000000002');

DELETE FROM quote_items
WHERE id IN ('13000000-0000-0000-0000-000000000011', '13000000-0000-0000-0000-000000000012');

DELETE FROM quotes
WHERE id = '13000000-0000-0000-0000-000000000001';

DELETE FROM stock_levels
WHERE org_id = '00000000-0000-0000-0000-000000000001'
  AND product_id IN (
      '12000000-0000-0000-0000-000000000001',
      '12000000-0000-0000-0000-000000000002',
      '12000000-0000-0000-0000-000000000003'
  );

DELETE FROM products
WHERE id IN (
    '12000000-0000-0000-0000-000000000001',
    '12000000-0000-0000-0000-000000000002',
    '12000000-0000-0000-0000-000000000003',
    '12000000-0000-0000-0000-000000000004',
    '12000000-0000-0000-0000-000000000005'
);

DELETE FROM suppliers
WHERE id IN ('11000000-0000-0000-0000-000000000001', '11000000-0000-0000-0000-000000000002');

DELETE FROM customers
WHERE id IN (
    '10000000-0000-0000-0000-000000000001',
    '10000000-0000-0000-0000-000000000002',
    '10000000-0000-0000-0000-000000000003'
);

UPDATE tenant_settings
   SET next_quote_number = 1,
       next_sale_number = 1,
       updated_at = now()
 WHERE org_id = '00000000-0000-0000-0000-000000000001';
